var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"수, 수아야!","JPN":"コ、コトリちゃん！","ENG":"S-Skia!","TWN":"蘇…蘇亞！"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"시스템 재부팅이 생각보다 오래 걸렸네. 상황이 끝났을 줄은 몰랐어.","JPN":"システムの再起動に思ったよりも時間がかかったね。\\n状況が終わっているとは予想できなかったよ。","ENG":"Rebooting the system took longer than expected. I did not expect the situation to be over.","TWN":"系統重啟的時間有點久，竟然都處理完了。"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"아니면…… 너희가 금방 끝낸 건가?","JPN":"それとも……アナタたちが終わらせるのが早かった？","ENG":"Or... Did you guys take care of it quickly?","TWN":"還是……是你們動作太快？"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"수아야! 괜찮은 거야?","JPN":"コトリ！　大丈夫？","ENG":"Skia! Are you all right?","TWN":"蘇亞！你沒事嗎？"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"아까 초기화 한다고 그러지 않았어……?","JPN":"さっき初期化って言ってなかった……？","ENG":"Didn’t they say that they were resetting you?","TWN":"他們剛剛不是說把你初始化嗎……？"},"stage":{"bg":"NEWTOWN","slots":{"L":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_PRIDE"}}}},{"id":"L9_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"언젠가 이런 일이 벌어질 걸 계산했어. 행동을 보면 생각이 읽히니까.","JPN":"いつかこんなことも起こり得ることを計算してた。\\n行動を見れば考えが読めるから。","ENG":"I calculated that this would happen someday. If you see their actions, you can determine their thoughts.","TWN":"我早就料到會有這種事發生，因為從他們的行動，就可以知道他們在想什麼。"},"stage":{"bg":"NEWTOWN","slots":{"L":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"단순히 초기화 버튼하고 재부팅 버튼 위치를 바꿨을 뿐인데. 전혀 눈치 못 챘나 봐.","JPN":"単純に初期化ボタンと再起動ボタンの位置を入れ替えただけなのに。全然気づかなかったみたい。","ENG":"I simply changed the locations of the reset button and the reboot button. They must not have caught on.","TWN":"於是我就將初始化和重啟按鈕的位置對調，看來他們完全沒發現。"},"stage":{"bg":"NEWTOWN","slots":{"L":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"와…… 수아 멋있어. 그런 것도 할 줄 알고…….","JPN":"わぁ……コトリちゃんかっこいい。そんなこともできるんだ……","ENG":"You’re amazing Skia... You even know how to do that.","TWN":"哇……蘇亞你好厲害喔，竟然還有這招……"},"stage":{"bg":"NEWTOWN","slots":{"L":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"그러게. 만지는 기계마다 고장난다고 건들지도 않으려고 했는데.","JPN":"そうだな。機械は触ると壊れるからって触れようとすらしてなかったのに。","ENG":"Tell me about it. You said that every machine you touch breaks down, so you tried to avoid touching them at all.","TWN":"對啊，你之前還說被你碰過的機器都會壞掉，所以不想碰的。"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"뇌에 기계를 연결했으니까 나도 적용을…… 아니 적응을 할 수 있게 된 거지.","JPN":"脳に機械を繋いでいるからワタシも適用……いや、適応してきたんだと思う。","ENG":"Since a machine is connected to my brain, I also applied... I mean I adapted to it.","TWN":"畢竟我的腦袋現在就連接著機器……自然而然會適應吧？"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"이게…… 무슨 감정인지는 제대로 말하기 어렵지만.","JPN":"これが……どんな感情かは言葉にしづらいけど。","ENG":"Although I cannot explain what emotion this is.","TWN":"這種感覺……不太好形容。"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"지금도 괜찮아. 나름 알아볼 수 있는 보조 장치도 있고.","JPN":"今のままでもいいよ。それなりに伝わる補助装置もあるし。","ENG":"It’s good as it is. There’s even a support device that shows them relatively well.","TWN":"沒關係，有可以明白你的感覺的輔助裝置。"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"그나저나 그 사람들…… 우릴 쫓아올까?","JPN":"それにしてもあの人たち……私たちを追いかけてくるのかな？","ENG":"By the way, those people... Will they chase after us?","TWN":"不過……那些人會來抓我們嗎？"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"확률은 있지만, 현장을 보면…… 몸 사릴 시간은 있지 않을까 싶네.","JPN":"可能性はあるけど、現場を見れば……\\nしばらく休める時間はあるんじゃないかな。","ENG":"There is a probability but once they see this scene... I think we may have some time to catch our breath.","TWN":"有可能，不過從現場的情況看來……我們或許還有一些時間可以脫身。"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"워낙 참혹해서 말이지.","JPN":"見るも無残な状況だからね。","ENG":"It is quite a messy scene.","TWN":"畢竟現場慘不忍睹。"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"그, 그런가…….","JPN":"そ、そうかな……","ENG":"Y-you think so?","TWN":"是嗎……"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"그래도 대비는 해야 할 거야. 집요한 놈들인 거 잘 알잖아.","JPN":"でも何かしら備えるべきだと思う。しつこい連中ってことはよくわかってるでしょ。","ENG":"We should still be prepared. You know fully well that they’re a stubborn bunch.","TWN":"我們還是必須有備無患，你也知道那些傢伙有多死纏爛打！"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"PUPPET_NPC_SUPPLEMENT_NULL","text":{"KOREA":"도망친 애들 싹 다 잡아 갔지.","JPN":"逃げた子たちだって全員捕まっちゃったし。","ENG":"They captured all the kids who ran away.","TWN":"逃走的人都會被他們一個一個抓回來。"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"PUPPET_NPC_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};